/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications via email.
 * The notification service checks these preferences before dispatching
 * to email adapters.
 */

import type { NotificationType } from './notification.js';

/**
 * Email delivery frequency.
 * - 'immediate': send as soon as the event occurs
 * - 'daily-digest': batch into a daily summary (not yet implemented)
 * - 'weekly-digest': batch into a weekly summary (not yet implemented)
 * - 'none': do not send email notifications
 */
export type EmailFrequency = 'immediate' | 'daily-digest' | 'weekly-digest' | 'none';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Master toggle for email notifications. */
  enabled: boolean;
  /** How often email notifications are delivered. */
  frequency: EmailFrequency;
  /** Notification categories the user is subscribed to. */
  subscribedCategories: NotificationType[];
}

/**
 * All notification categories a user can subscribe to.
 */
export const ALL_NOTIFICATION_CATEGORIES: NotificationType[] = [
  'order:confirmation',
  'order:status-update',
  'user:welcome',
  'user:profile-updated',
];

/**
 * User notification preferences — persisted per user.
 */
export interface UserNotificationPreferences {
  id: string;
  userId: string;
  email: EmailPreferences;
  updatedAt: Date;
}

/**
 * Input for updating email preferences.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailFrequency;
  subscribedCategories?: NotificationType[];
}

/**
 * Returns default email preferences (all enabled, immediate delivery).
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Repository for UserNotificationPreferences data access.
 *
 * Extends BaseRepository with preferences-specific query methods.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import type { EmailFrequency } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: {
        enabled: record['emailEnabled'] as boolean,
        frequency: record['emailFrequency'] as EmailFrequency,
        subscribedCategories: JSON.parse(record['emailSubscribedCategories'] as string) as NotificationType[],
      },
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      emailEnabled: entity.email.enabled,
      emailFrequency: entity.email.frequency,
      emailSubscribedCategories: JSON.stringify(entity.email.subscribedCategories),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences by user ID.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    const results = this.findAll((prefs) => prefs.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for notification preferences and exposes
 * a method for the notification service to check whether a given
 * notification should be delivered to a user.
 *
 * Depends on:
 * - PreferencesRepository for data access
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type {
  UserNotificationPreferences,
  UpdateEmailPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import { getDefaultEmailPreferences } from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns defaults if none are persisted.
   */
  getPreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    return {
      id: '',
      userId,
      email: getDefaultEmailPreferences(),
      updatedAt: new Date(),
    };
  }

  /**
   * Update email preferences for a user. Creates preferences if they
   * don't exist yet.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);

    if (existing) {
      const updated: UserNotificationPreferences = {
        ...existing,
        email: {
          enabled: input.enabled ?? existing.email.enabled,
          frequency: input.frequency ?? existing.email.frequency,
          subscribedCategories:
            input.subscribedCategories ?? existing.email.subscribedCategories,
        },
        updatedAt: new Date(),
      };
      this.preferencesRepository.update(existing.id, updated);
      this.logger.info(`Updated email preferences for user ${userId}`);
      return updated;
    }

    const defaults = getDefaultEmailPreferences();
    const prefs: UserNotificationPreferences = {
      id: generatePreferencesId(),
      userId,
      email: {
        enabled: input.enabled ?? defaults.enabled,
        frequency: input.frequency ?? defaults.frequency,
        subscribedCategories:
          input.subscribedCategories ?? defaults.subscribedCategories,
      },
      updatedAt: new Date(),
    };
    this.preferencesRepository.save(prefs);
    this.logger.info(`Created email preferences for user ${userId}`);
    return prefs;
  }

  /**
   * Check whether an email notification of the given type should be
   * sent to the specified user based on their preferences.
   *
   * Returns true if:
   * - The user has no persisted preferences (defaults allow all)
   * - Email is enabled AND the category is subscribed AND frequency is not 'none'
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const prefs = this.preferencesRepository.findByUserId(userId);

    // No preferences stored — use defaults (everything enabled)
    if (!prefs) {
      return true;
    }

    if (!prefs.email.enabled) {
      this.logger.info(`Email disabled for user ${userId}, skipping ${notificationType}`);
      return false;
    }

    if (prefs.email.frequency === 'none') {
      this.logger.info(`Email frequency is none for user ${userId}, skipping ${notificationType}`);
      return false;
    }

    if (!prefs.email.subscribedCategories.includes(notificationType)) {
      this.logger.info(
        `User ${userId} not subscribed to ${notificationType}, skipping`,
      );
      return false;
    }

    return true;
  }
}

